1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  amulet: 60,
19	  sword: 100,
20	};
21	
22	const FIRST_INSURANCE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	
31	function sumOver<T>(xs: T[], f: (x: T) => number): number {
32	  return xs.reduce((total, x) => total + f(x), 0);
33	}
34	
35	function itemBasePremium(item: QuoteItem): number {
36	  return BASE_PREMIUM[item.type] ?? 0;
37	}
38	
39	function itemSurcharges(item: QuoteItem): number {
40	  const base = itemBasePremium(item);
41	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
42	  const highEnchantmentSurcharge =
43	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
44	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
45	      : 0;
46	  return curseSurcharge + highEnchantmentSurcharge;
47	}
48	
49	function priceQuoteStep(
50	  step: QuoteStep,
51	  yearsWithMHPCO: number,
52	): { premium: number } {
53	  const policyBase = sumOver(step.items, itemBasePremium);
54	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
55	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
56	  const loyaltyDiscount =
57	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
58	      ? policyBase * LOYALTY_DISCOUNT_RATE
59	      : 0;
60	  const premium = Math.ceil(
61	    policyBase +
62	      itemSurchargeTotal +
63	      firstInsurance -
64	      loyaltyDiscount +
65	      PROCESSING_FEE,
66	  );
67	  return { premium };
68	}
69	
70	export function runScenario(scenario: Scenario): {
71	  results: { premium: number }[];
72	} {
73	  const results = scenario.steps.map((step) =>
74	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO),
75	  );
76	  return { results };
77	}
